create table if not exists hr_leave_balances (id uuid primary key, tenant_id varchar(64) not null default 'default', employee_id uuid not null, leave_type varchar(40) not null, year integer, total_days double precision not null default 0, used_days double precision not null default 0, created_at timestamp with time zone not null default current_timestamp, updated_at timestamp with time zone not null default current_timestamp, created_by varchar(64), updated_by varchar(64));
create table if not exists hr_leave_requests (id uuid primary key, tenant_id varchar(64) not null default 'default', employee_id uuid not null, leave_type varchar(40) not null, start_date date not null, end_date date not null, total_days double precision not null, reason varchar(1000), status varchar(32) not null default 'PENDING', approved_by varchar(80), approved_at timestamp, approval_remark varchar(1000), created_at timestamp with time zone not null default current_timestamp, updated_at timestamp with time zone not null default current_timestamp, created_by varchar(64), updated_by varchar(64));
create table if not exists hr_emergency_contacts (id uuid primary key, tenant_id varchar(64) not null default 'default', employee_id uuid not null, name varchar(80) not null, relationship varchar(40), phone varchar(40), address varchar(200), is_primary boolean not null default false, remark varchar(1000), created_at timestamp with time zone not null default current_timestamp, updated_at timestamp with time zone not null default current_timestamp, created_by varchar(64), updated_by varchar(64));
create table if not exists hr_employee_education (id uuid primary key, tenant_id varchar(64) not null default 'default', employee_id uuid not null, school_name varchar(200) not null, degree varchar(40), major varchar(200), start_date date, end_date date, is_highest boolean not null default false, remark varchar(1000), created_at timestamp with time zone not null default current_timestamp, updated_at timestamp with time zone not null default current_timestamp, created_by varchar(64), updated_by varchar(64));
create table if not exists hr_employee_lifecycle_records (id uuid primary key, tenant_id varchar(64) not null default 'default', employee_id uuid not null, lifecycle_type varchar(40) not null, effective_date date not null, from_organization_id varchar(64), from_organization_name varchar(200), from_position varchar(120), to_organization_id varchar(64), to_organization_name varchar(200), to_position varchar(120), reason varchar(1000), status varchar(32) not null default 'PENDING', approved_by varchar(80), approved_at date, remark varchar(1000), created_at timestamp with time zone not null default current_timestamp, updated_at timestamp with time zone not null default current_timestamp, created_by varchar(64), updated_by varchar(64));
create table if not exists hr_employee_work_experience (id uuid primary key, tenant_id varchar(64) not null default 'default', employee_id uuid not null, company_name varchar(200) not null, position_name varchar(120), start_date date, end_date date, is_current boolean not null default false, description varchar(1000), remark varchar(1000), created_at timestamp with time zone not null default current_timestamp, updated_at timestamp with time zone not null default current_timestamp, created_by varchar(64), updated_by varchar(64));
